import{_ as a,c as i,o,a1 as t}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Preguntas Frecuentes: Autenticación OAuth y Solución de Problemas de Modelos | Antigravity Auth","description":"Descubre las preguntas frecuentes y soluciones del plugin Antigravity Auth. Cubre la resolución de fallos de autenticación OAuth, el manejo de errores de modelo no encontrado, la configuración de compatibilidad de plugins y guías prácticas para ayudarte a localizar y resolver rápidamente varios problemas encontrados durante el uso.","frontmatter":{"title":"Preguntas Frecuentes: Autenticación OAuth y Solución de Problemas de Modelos | Antigravity Auth","sidebarTitle":"Qué hacer si falla la autenticación","subtitle":"Preguntas Frecuentes: Autenticación OAuth y Solución de Problemas de Modelos","description":"Descubre las preguntas frecuentes y soluciones del plugin Antigravity Auth. Cubre la resolución de fallos de autenticación OAuth, el manejo de errores de modelo no encontrado, la configuración de compatibilidad de plugins y guías prácticas para ayudarte a localizar y resolver rápidamente varios problemas encontrados durante el uso.","order":4},"headers":[],"relativePath":"es/NoeFabris/opencode-antigravity-auth/faq/index.md","filePath":"es/NoeFabris/opencode-antigravity-auth/faq/index.md"}'),r={name:"es/NoeFabris/opencode-antigravity-auth/faq/index.md"};function n(l,e,d,s,c,u){return o(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="preguntas-frecuentes" tabindex="-1">Preguntas Frecuentes <a class="header-anchor" href="#preguntas-frecuentes" aria-label="Permalink to &quot;Preguntas Frecuentes&quot;">​</a></h1><p>Este capítulo recopila los problemas más comunes y sus soluciones al usar el plugin Antigravity Auth. Ya sea por fallos de autenticación OAuth, errores en solicitudes de modelo, o problemas de compatibilidad de plugins, aquí encontrarás las guías correspondientes para la resolución de problemas.</p><h2 id="requisitos-previos" tabindex="-1">Requisitos Previos <a class="header-anchor" href="#requisitos-previos" aria-label="Permalink to &quot;Requisitos Previos&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Antes de comenzar, asegúrate de</p><ul><li>✅ Haber completado la <a href="./../start/quick-install/">instalación rápida</a> y agregado exitosamente tu cuenta</li><li>✅ Haber completado la <a href="./../start/first-auth-login/">primera autenticación</a> y comprendido el flujo OAuth</li></ul></div><h2 id="ruta-de-aprendizaje" tabindex="-1">Ruta de Aprendizaje <a class="header-anchor" href="#ruta-de-aprendizaje" aria-label="Permalink to &quot;Ruta de Aprendizaje&quot;">​</a></h2><p>Según el tipo de problema que encuentres, selecciona la guía de resolución correspondiente:</p><h3 id="_1-resolucion-de-fallos-de-autenticacion-oauth" tabindex="-1">1. <a href="./common-auth-issues/">Resolución de fallos de autenticación OAuth</a> <a class="header-anchor" href="#_1-resolucion-de-fallos-de-autenticacion-oauth" aria-label="Permalink to &quot;1. [Resolución de fallos de autenticación OAuth](./common-auth-issues/)&quot;">​</a></h3><p>Resuelve problemas comunes relacionados con la autenticación OAuth, la actualización de tokens y las cuentas.</p><ul><li>La autorización del navegador tiene éxito pero el terminal indica &quot;autorización fallida&quot;</li><li>De repente aparece el error &quot;Permission Denied&quot; o &quot;invalid_grant&quot;</li><li>Fallo del callback OAuth en el navegador Safari</li><li>No se puede completar la autenticación en entornos WSL2/Docker</li></ul><h3 id="_2-migracion-de-cuentas" tabindex="-1">2. <a href="./migration-guide/">Migración de cuentas</a> <a class="header-anchor" href="#_2-migracion-de-cuentas" aria-label="Permalink to &quot;2. [Migración de cuentas](./migration-guide/)&quot;">​</a></h3><p>Migra cuentas entre diferentes máquinas y maneja las actualizaciones de versión.</p><ul><li>Migrar cuenta de la computadora vieja a la nueva</li><li>Comprender los cambios en el formato de almacenamiento (v1/v2/v3)</li><li>Resolver errores de invalid_grant después de la migración</li></ul><h3 id="_3-resolucion-de-modelo-no-encontrado" tabindex="-1">3. <a href="./model-not-found/">Resolución de modelo no encontrado</a> <a class="header-anchor" href="#_3-resolucion-de-modelo-no-encontrado" aria-label="Permalink to &quot;3. [Resolución de modelo no encontrado](./model-not-found/)&quot;">​</a></h3><p>Resuelve problemas relacionados con modelos, como modelo no encontrado y errores 400.</p><ul><li>Resolución de error &quot;Model not found&quot;</li><li>Error 400 &quot;Invalid JSON payload received. Unknown name &quot;parameters&quot;&quot;</li><li>Error en la llamada del servidor MCP</li></ul><h3 id="_4-compatibilidad-de-plugins" tabindex="-1">4. <a href="./plugin-compatibility/">Compatibilidad de plugins</a> <a class="header-anchor" href="#_4-compatibilidad-de-plugins" aria-label="Permalink to &quot;4. [Compatibilidad de plugins](./plugin-compatibility/)&quot;">​</a></h3><p>Resuelve problemas de compatibilidad con plugins como oh-my-opencode, DCP, etc.</p><ul><li>Configurar correctamente el orden de carga de plugins</li><li>Desactivar métodos de autenticación conflictivos en oh-my-opencode</li><li>Habilitar desplazamiento PID para escenarios de agentes paralelos</li></ul><h3 id="_5-advertencia-tos" tabindex="-1">5. <a href="./tos-warning/">Advertencia ToS</a> <a class="header-anchor" href="#_5-advertencia-tos" aria-label="Permalink to &quot;5. [Advertencia ToS](./tos-warning/)&quot;">​</a></h3><p>Comprende los riesgos de uso y evita que la cuenta sea bloqueada.</p><ul><li>Conocer las restricciones de los términos de servicio de Google</li><li>Identificar escenarios de alto riesgo (nuevas cuentas, solicitudes intensivas)</li><li>Dominar las mejores prácticas para evitar el bloqueo de cuentas</li></ul><h2 id="localizacion-rapida-de-problemas" tabindex="-1">Localización Rápida de Problemas <a class="header-anchor" href="#localizacion-rapida-de-problemas" aria-label="Permalink to &quot;Localización Rápida de Problemas&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Fenómeno de error</th><th>Lectura recomendada</th></tr></thead><tbody><tr><td>Fallo de autenticación, tiempo de espera de autorización</td><td><a href="./common-auth-issues/">Resolución de fallos de autenticación OAuth</a></td></tr><tr><td>invalid_grant, Permission Denied</td><td><a href="./common-auth-issues/">Resolución de fallos de autenticación OAuth</a></td></tr><tr><td>Model not found, error 400</td><td><a href="./model-not-found/">Resolución de modelo no encontrado</a></td></tr><tr><td>Conflicto con otros plugins</td><td><a href="./plugin-compatibility/">Compatibilidad de plugins</a></td></tr><tr><td>Cambio de computadora, actualización de versión</td><td><a href="./migration-guide/">Migración de cuentas</a></td></tr><tr><td>Preocupado por la seguridad de la cuenta</td><td><a href="./tos-warning/">Advertencia ToS</a></td></tr></tbody></table><h2 id="siguiente-paso" tabindex="-1">Siguiente Paso <a class="header-anchor" href="#siguiente-paso" aria-label="Permalink to &quot;Siguiente Paso&quot;">​</a></h2><p>Después de resolver el problema, puedes:</p><ul><li>📖 Leer <a href="./../advanced/">Funciones avanzadas</a> para dominar a fondo múltiples cuentas, recuperación de sesiones y otras características</li><li>📚 Consultar <a href="./../appendix/">Apéndice</a> para conocer el diseño de arquitectura y referencia completa de configuración</li><li>🔄 Seguir el <a href="./../changelog/">registro de cambios</a> para obtener las últimas funciones y actualizaciones</li></ul>',26)])])}const h=a(r,[["render",n]]);export{m as __pageData,h as default};
